css:
.demo-card {
  background: #2a2a2a;
  color: #fff;
  padding: 24px;
  border-radius: 12px;
  box-shadow: 0 4px 6px rgba(0,0,0,0.3);
  font-family: system-ui, sans-serif;
  max-width: 300px;
  text-align: center;
}
.demo-card h2 {
  margin-top: 0;
  color: #4ade80;
}
.demo-card button {
  background: #4ade80;
  color: #000;
  border: none;
  padding: 10px 20px;
  border-radius: 6px;
  font-weight: bold;
  cursor: pointer;
  transition: opacity 0.2s;
}
.demo-card button:hover {
  opacity: 0.8;
}
